export function getRuleDefinition(code) {
    return RULE_DEFINITIONS[code];
}
export function listRuleDefinitions() {
    return Object.values(RULE_DEFINITIONS);
}
function rule(code, defaultSeverity, source, title, spec) {
    return {
        code,
        defaultSeverity,
        source,
        title,
        spec,
    };
}
